export const redeemReferralCode = async (playerUid: string, code: string) => {
    const codeUpper = code.toUpperCase();

    // Find owner of the code
    const usersRef = rtdb.ref('users');
    const snapshot = await usersRef.orderByChild('referralCode').equalTo(codeUpper).limitToFirst(1).once('value');

    let referrerUid: string | null = null;
    if (snapshot.exists()) {
        referrerUid = Object.keys(snapshot.val())[0];
    }

    if (!referrerUid) {
        throw new Error("Invalid referral code.");
    }
    if (referrerUid === playerUid) {
        throw new Error("You cannot use your own referral code.");
    }

    const playerRef = rtdb.ref(`users/${playerUid}`);
    const referrerRef = rtdb.ref(`users/${referrerUid}`);

    // Update Player (Redeemer)
    const { committed: playerCommitted } = await playerRef.transaction(p => {
        if (p) {
            if (p.redeemedReferral) return; // Already redeemed
            p.redeemedReferral = true;
            p.coins = (p.coins || 0) + 500; // Bonus for new player
        }
        return p;
    });

    if (!playerCommitted) {
        throw new Error("You have already redeemed a referral code.");
    }

    // Update Referrer
    await referrerRef.transaction(r => {
        if (r) {
            r.referralCount = (r.referralCount || 0) + 1;
            r.coins = (r.coins || 0) + 1000; // Bonus for referrer
        }
        return r;
    });
};

