// Helper to normalize bird stats for Esports/Ranked fairness
const normalizeBirdStats = (originalBird: Bird, targetLevel: number = 10): Bird => {
    const def = BIRD_DEFINITIONS[originalBird.id];
    if (!def) return originalBird;

    return {
        ...originalBird,
        level: targetLevel,
        // Calculate stats based on base + (growth * level)
        skillPower: def.baseAttackPower + (def.attackPowerPerLevel * (targetLevel - 1)),
        maxHealth: def.baseHealth + (def.healthPerLevel * (targetLevel - 1)),
        xp: 0,
        xpToNextLevel: 0
    };
};

export const findMatch = async (player: Player, onMatchFound: (match: Match) => void, onError: (error: Error) => void, matchType: 'rank' | 'classic', entryFee: number, selectedBird: Bird) => {
  const playerDocRef = rtdb.ref(`users/${player.uid}`);
  const queueRef = rtdb.ref(`queue/${matchType}`);
  const userQueueRef = rtdb.ref(`queue/${matchType}/${player.uid}`);

  try {
    const playerData = player;

    if ((playerData.coins ?? 0) < entryFee) {
      throw new Error(`Not enough coins to join. You need ${entryFee}.`);
    }

    // Deduct entry fee before starting matchmaking
    if (entryFee > 0) {
      await playerDocRef.child('coins').set(firebase.database.ServerValue.increment(-entryFee));
    }

    // Set onDisconnect here. If we find a match or cancel, we'll remove it.
    userQueueRef.onDisconnect().remove();

    let foundOpponent: any = null;

    const transaction = await queueRef.transaction((queue) => {
      foundOpponent = null;

      if (queue === null) {
        queue = {};
      }

      let opponentId: string | null = null;

      // Simplified matchmaking for now
      for (const uid in queue) {
          if (Object.prototype.hasOwnProperty.call(queue, uid) && uid !== player.uid) {
              opponentId = uid;
              break;
          }
      }

      if (opponentId) {
        // Found opponent, capture their data and remove them from the queue
        foundOpponent = queue[opponentId];
        delete queue[opponentId];
      } else {
        // No opponent, add myself to the queue
        queue[player.uid] = { 
          uid: player.uid,
          playerData,
          selectedBird,
          timestamp: firebase.database.ServerValue.TIMESTAMP 
        };
      }
      return queue;
    });

    if (!transaction.committed) {
      throw new Error("Matchmaking failed due to high server load. Please try again.");
    }

    if (foundOpponent) {
      // We found a match, now create it.
      const opponentData = foundOpponent.playerData as Player;
      let opponentBird = foundOpponent.selectedBird as Bird;
      let myBird = selectedBird;

      // --- ESPORTS FAIRNESS: NORMALIZE STATS FOR RANKED ---
      if (matchType === 'rank') {
          opponentBird = normalizeBirdStats(opponentBird);
          myBird = normalizeBirdStats(myBird);
      }

      const [myClanTag, opponentClanTag] = await Promise.all([
        getClanTag(playerData.clanId),
        getClanTag(opponentData.clanId)
      ]);

      const matchId = `match_${Date.now()}`;
      const newMatch: Match = {
        id: matchId,
        player1: { uid: player.uid, displayName: player.displayName, photoURL: player.photoURL, damageDealt: 0, rankPoints: playerData.rankPoints, clanId: playerData.clanId || null, clanTag: myClanTag, selectedBird: myBird, currentHealth: myBird.maxHealth, activeBadge: playerData.activeBadge || null, equippedEmotes: player.equippedEmotes || [], abilityCooldownLeft: 0, abilityUsesLeft: 2, activeEffects: {}, healUsesLeft: 2 },
        player2: { uid: opponentData.uid, displayName: opponentData.displayName, photoURL: opponentData.photoURL, damageDealt: 0, rankPoints: opponentData.rankPoints, clanId: opponentData.clanId || null, clanTag: opponentClanTag, selectedBird: opponentBird, currentHealth: opponentBird.maxHealth, activeBadge: opponentData.activeBadge || null, equippedEmotes: opponentData.equippedEmotes || [], abilityCooldownLeft: 0, abilityUsesLeft: 2, activeEffects: {}, healUsesLeft: 2 },
        status: 'active',
        winner: null,
        createdAt: Date.now(),
        startTime: Date.now(),
        matchType: matchType,
        matchMode: '1v1',
        turn: 1,
        currentTurnPlayerUid: player.uid, // Player 1 starts
        log: [`Match between ${player.displayName || 'P1'} and ${opponentData.displayName || 'P2'} begins!`],
      };

      await rtdb.ref(`matches/${matchId}`).set(newMatch);
      await rtdb.ref(`player_matches/${player.uid}`).set(matchId);
      await rtdb.ref(`player_matches/${opponentData.uid}`).set(matchId);

      userQueueRef.onDisconnect().cancel();
    }

  } catch (error: any) {
    console.error("Error during matchmaking process:", error);
    if(entryFee > 0) {
      await playerDocRef.child('coins').set(firebase.database.ServerValue.increment(entryFee));
    }
    userQueueRef.onDisconnect().cancel();
    await userQueueRef.remove();
    throw error;
  }

  const playerMatchRef = rtdb.ref(`player_matches/${player.uid}`);
  playerMatchRef.on('value', async (snapshot) => {
    if (snapshot.exists()) {
      const matchId = snapshot.val();
      const matchDataRef = rtdb.ref(`matches/${matchId}`);
      const matchSnapshot = await matchDataRef.get();
      if (matchSnapshot.exists()){
         onMatchFound(matchSnapshot.val());
         playerMatchRef.off();
         userQueueRef.remove();
         userQueueRef.onDisconnect().cancel();
         playerMatchRef.remove();
      }
    }
  }, (error: Error) => {
    console.error("Match listener failed:", error);
    onError(error);
  });
};

