    const [activeTab, setActiveTab] = useState<Tab>('CHALLENGE');
    const [selectedMode, setSelectedMode] = useState<'rank' | 'minigame'>('rank');
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isTopUpModalOpen, setIsTopUpModalOpen] = useState(false);
    const [isMailboxOpen, setIsMailboxOpen] = useState(false);
    const [mailItems, setMailItems] = useState<MailItem[]>([]);
    const [matchmakingTime, setMatchmakingTime] = useState(0);
    const matchmakingIntervalRef = useRef<number | null>(null);

    const [hasUnreadGlobalMessages, setHasUnreadGlobalMessages] = useState(false);

    const { notifications } = useRealtime();
    const [viewingProfileUid, setViewingProfileUid] = useState<string | null>(null);
    const [matchmakingError, setMatchmakingError] = useState<string | null>(null);
    const [isClaiming, setIsClaiming] = useState(false);
    const [membershipModalInfo, setMembershipModalInfo] = useState<{type: 'weekly' | 'monthly'} | null>(null);
    const [isWinterverseModalOpen, setIsWinterverseModalOpen] = useState(false);
    const [isEventsModalOpen, setIsEventsModalOpen] = useState(false);
    const musicStarted = useRef(false);

    const isMatchmakingRef = useRef(isMatchmaking);
    useEffect(() => {
        isMatchmakingRef.current = isMatchmaking;
    }, [isMatchmaking]);

    useEffect(() => {
        if (isMatchmaking) {
            setMatchmakingTime(0);
            matchmakingIntervalRef.current = window.setInterval(() => {
                setMatchmakingTime(prev => prev + 1);
            }, 1000);
        } else {
            if (matchmakingIntervalRef.current) {
                clearInterval(matchmakingIntervalRef.current);
                matchmakingIntervalRef.current = null;
            }
        }

        return () => {
            if (matchmakingIntervalRef.current) {
                clearInterval(matchmakingIntervalRef.current);
            }
        };
    }, [isMatchmaking]);

    useEffect(() => {
        const hideModal = sessionStorage.getItem('hideWinterverseModal') === 'true';
        if (!hideModal) {
            // Add a small delay to make it feel less abrupt on login
            setTimeout(() => setIsWinterverseModalOpen(true), 1000);
        }
    }, []);

    const formatTime = (seconds: number) => {
        const minutes = Math.floor(seconds / 60);
        const remainingSeconds = seconds % 60;
        return `${String(minutes).padStart(2, '0')}:${String(remainingSeconds).padStart(2, '0')}`;
    };

    const NOTIF_STORAGE_KEY = `birdclash-lastReadNotifTimestamp-${playerData.uid}`;
    const hasUnreadGlobalNotifs = useMemo(() => {
        if (notifications.length > 0) {
            const lastReadTimestamp = parseInt(localStorage.getItem(NOTIF_STORAGE_KEY) || '0', 10);
            return notifications[0].timestamp > lastReadTimestamp;
        }
        return false;
    }, [notifications, NOTIF_STORAGE_KEY]);

    useEffect(() => {
        const unsub = playerService.listenToMail(playerData.uid, setMailItems);
        return () => unsub();
    }, [playerData.uid]);

    const hasUnreadMail = useMemo(() => mailItems.some(item => item.status === 'unread'), [mailItems]);

    const isWeeklyActive = playerData.weeklyMembershipExpires && playerData.weeklyMembershipExpires > Date.now();
    const isMonthlyActive = playerData.monthlyMembershipExpires && playerData.monthlyMembershipExpires > Date.now();

    useEffect(() => {
        const audioEl = document.getElementById('lobby-music') as HTMLAudioElement;
        if (!audioEl) return;

        const targetUrl = config.lobbyMusicUrl || 'https://cdn.pixabay.com/download/audio/2022/08/04/audio_2d81b016b8.mp3';
        if (audioEl.src !== targetUrl) {
            audioEl.src = targetUrl;
            audioEl.load();
        }

        audioEl.volume = musicVolume;

        const playMusic = () => {
            if (musicStarted.current || !audioEl.paused) {
                // If music is already considered started or is not paused, cleanup and exit.
                document.removeEventListener('click', playMusic);
                document.removeEventListener('touchstart', playMusic);
                return;
            }

            const playPromise = audioEl.play();
            if (playPromise !== undefined) {
                playPromise.then(() => {
                    musicStarted.current = true;
                    // On success, cleanup listeners.
                    document.removeEventListener('click', playMusic);
                    document.removeEventListener('touchstart', playMusic);
                }).catch(error => {
                    console.log("Lobby music autoplay prevented. Awaiting user interaction.");
                    // On failure, ensure listeners are attached (they are added below).
                });
            }
        };

        // Attach interaction listeners immediately as a fallback for autoplay policies.
        // They will be removed once music successfully plays.
        document.addEventListener('click', playMusic, { once: true });
        document.addEventListener('touchstart', playMusic, { once: true });

        // Attempt to play right away.
        playMusic();

        // Cleanup function for when the component unmounts.
        return () => {
            if (audioEl) {
                audioEl.pause();
            }
            musicStarted.current = false; // Reset for next time dashboard mounts.
            document.removeEventListener('click', playMusic);
            document.removeEventListener('touchstart', playMusic);
        };
    }, [musicVolume, config.lobbyMusicUrl]);

    const hasClaimableQuests = useMemo(() => {
        if (!playerData.quests) return false;
        return DAILY_QUESTS.some(quest => {
            const progress = playerData.quests?.progress[quest.id];
            return progress && progress.progress >= quest.target && !progress.claimed;
        });
    }, [playerData.quests]);

    const isDailyClaimAvailable = useMemo(() => {
        const now = Date.now();
        const todayStr = new Date(now).toISOString().split('T')[0];
        const weeklyActive = playerData.weeklyMembershipExpires && playerData.weeklyMembershipExpires > now;
        const weeklyClaimed = playerData.weeklyClaims?.includes(todayStr);
        const monthlyActive = playerData.monthlyMembershipExpires && playerData.monthlyMembershipExpires > now;
        const monthlyClaimed = playerData.monthlyClaims?.includes(todayStr);
        return (weeklyActive && !weeklyClaimed) || (monthlyActive && !monthlyClaimed);
    }, [playerData]);

    const equippedBird = useMemo(() => {
        if (!playerData.ownedBirds) return null;
        const birdId = playerData.equippedBirdId;
        if (birdId && playerData.ownedBirds[birdId]) return playerData.ownedBirds[birdId];
        const allBirds = Object.values(playerData.ownedBirds);
        return allBirds.length > 0 ? allBirds[0] : null;
    }, [playerData.ownedBirds, playerData.equippedBirdId]);

    const handleToggleMailbox = () => {
        setIsMailboxOpen(prev => !prev);
        if (!isMailboxOpen && notifications.length > 0) {
            localStorage.setItem(NOTIF_STORAGE_KEY, notifications[0].timestamp.toString());
        }
    };

    const handleClaim = async () => {
        if (!playerData.uid) return;
        setIsClaiming(true);
        try { const message = await claimDailyMembershipRewards(playerData.uid); toast.success(message); } 
        catch (e: any) { toast.error(e.message); } 
        finally { setIsClaiming(false); }
    };

    const handleStartSoloMatchmaking = () => {
        if (playerData.isBlacklisted) {
            toast.warn("⚠️ This ID is under suspicious activity. You can’t play ranked matches at the moment.");
            return;
        }
        if (!equippedBird) { toast.error("Please equip a bird from your Collection first!"); return; }
        setMatchmakingError(null);
        const fee = config.RANK_ENTRY_FEE_COINS;
        if (playerData.coins < fee) {
            const errorMsg = `Not enough coins! You need ${fee} to play.`;
            setMatchmakingError(errorMsg);
            toast.error(errorMsg);
            return;
        }
        onStartMatchmaking();
    };

    const hasBirds = playerData.ownedBirds && Object.keys(playerData.ownedBirds).length > 0;
    const primeLevel = getPrimeLevel(playerData.totalGemsToppedUp);

    const renderPanelContent = () => {
        const panelProps = { player: playerData };
        switch(activeTab) {
            case 'STORE': return <StoreScreen {...panelProps} />;
            case 'BIRDS': return <BirdsScreen {...panelProps} />;
            case 'SOCIAL': return <SocialScreen player={playerData} onInviteFriend={props.onInviteFriend} onStartSpectating={props.onStartSpectating} onViewProfile={setViewingProfileUid} />;
            case 'PROFILE': return <ProfileScreen {...panelProps} />;
            case 'ROYALE_PASS': return <RoyalePassScreen {...panelProps} />;
            case 'ESPORTS': return <EsportsScreen {...panelProps} />;
            case 'LEADERBOARD': return <Leaderboard onViewProfile={setViewingProfileUid} />;
            case 'LUCK_ROYALE': return <LuckRoyaleScreen {...panelProps} />;
            case 'QUESTS': return <QuestsScreen {...panelProps} />;
            default: return null;
        }
    };

    const showContentPanel = activeTab !== 'CHALLENGE';

    return (
        <div className="w-full h-full flex flex-col relative" style={{ 
            backgroundImage: winterThemeActive 
                ? 'radial-gradient(ellipse at bottom, #1b2735 0%, #090a0f 100%)' 
                : `url('${lobbyBackground}')`,
            backgroundSize: 'cover',
            backgroundPosition: 'center'
        }}>
            {winterThemeActive && <Snowfall />}
            {/* Header */}
            <header className="px-2 py-2 flex-shrink-0 flex flex-wrap items-center justify-between gap-2 bg-black/30 border-b border-[var(--ff-border)] z-10">
                {/* Player Info */}
                <div className="flex items-center gap-2 flex-shrink-0">
                    <button onClick={() => setActiveTab('PROFILE')} className="flex items-center space-x-2 text-left">
                        <PlayerAvatar photoURL={playerData.photoURL} uid={playerData.uid} activeBadge={playerData.activeBadge} sizeClassName="w-10 h-10 md:w-12 md:h-12" imgClassName="border-2 border-gray-500"/>
                        <div>
                            <h2 className="text-xs sm:text-sm font-bold font-pixel whitespace-nowrap">{playerData.displayName || 'Player'}</h2>
                             <div className="w-24 h-3 bg-black/50 border border-gray-600 rounded-full mt-1">
                                <div 
                                  className="h-full bg-yellow-400 rounded-full text-black text-[8px] text-center font-bold" 
                                  style={{ width: `${((playerData.xp || 0) / (playerData.xpToNextLevel || 100)) * 100}%` }}
                                >
                                    LVL {playerData.level || 1}
                                </div>
                            </div>
                        </div>
                    </button>
                    {primeLevel > 0 && <PrimeLevelDisplay level={primeLevel} />}
                    <PlayerRankDisplay player={playerData} />
                </div>

                {/* Actions and Currency */}
                <div className="flex items-center justify-end flex-wrap gap-2 flex-grow">
                    {isDailyClaimAvailable && <Button onClick={handleClaim} disabled={isClaiming} variant="success" className="!py-1 !px-2 !text-xs animate-pulse">{isClaiming ? <Spinner /> : 'Claim'}</Button>}

                    <div className="ff-currency-box text-yellow-400 !text-sm !py-1 !px-2">💰 <AnimatedNumber value={playerData.coins} /></div>
                    <div className="ff-gem-box text-purple-400 !text-sm !py-1 !px-2 !pr-6">
                        <span>💎</span><AnimatedNumber value={playerData.gems} />
                        <button onClick={() => setIsTopUpModalOpen(true)} className="ff-topup-button" aria-label="Top up gems">+</button>
                    </div>

                    {isWeeklyActive && <div onClick={() => setMembershipModalInfo({ type: 'weekly' })} className="ff-membership-card glow-w !w-7 !h-9 !text-base" title={`Weekly Pass Active. Expires: ${new Date(playerData.weeklyMembershipExpires!).toLocaleDateString()}`}>W</div>}
                    {isMonthlyActive && <div onClick={() => setMembershipModalInfo({ type: 'monthly' })} className="ff-membership-card glow-m !w-7 !h-9 !text-base" title={`Monthly Pass Active. Expires: ${new Date(playerData.monthlyMembershipExpires!).toLocaleDateString()}`}>M</div>}

                    <div className="flex items-center gap-1">
                      <button onClick={handleToggleMailbox} className="p-2 rounded-full hover:bg-black/20" aria-label="Mailbox"><MailIcon hasUnread={hasUnreadMail || hasUnreadGlobalNotifs} /></button>
                      <button onClick={() => setIsSettingsOpen(true)} className="p-2 rounded-full hover:bg-black/20" aria-label="Settings"><SettingsIcon /></button>
                      <button onClick={() => auth.signOut()} className="p-2 rounded-full hover:bg-black/20 text-red-400" aria-label="Logout"><LogoutIcon /></button>
                    </div>
                </div>
            </header>

            {/* Main View */}
            <main className="flex-grow flex flex-row overflow-hidden">
                {/* Left Sidebar */}
                <div className="flex flex-col gap-2 justify-center p-2 sm:p-4">
                    <SidebarButton icon="📜" label="Quests" onClick={() => setActiveTab('QUESTS')} indicator={hasClaimableQuests} />
                    <SidebarButton icon="🎟️" label="Pass" onClick={() => setActiveTab('ROYALE_PASS')} />
                    <SidebarButton icon="🎰" label="Royale" onClick={() => setActiveTab('LUCK_ROYALE')} />
                    <SidebarButton icon="🏆" label="Ranks" onClick={() => setActiveTab('LEADERBOARD')} />
                    <SidebarButton icon="🏅" label="Esports" onClick={() => setActiveTab('ESPORTS')} />
                    <SidebarButton icon="🎉" label="Events" onClick={() => setIsEventsModalOpen(true)} indicator={true} />
                </div>

                {/* Central Content Area */}
                <div className="flex-grow flex flex-col gap-2 p-2 overflow-hidden">
                    <div className="flex-grow flex items-center justify-center bird-float pseudo-3d relative">
                        {equippedBird ? (
                            <div className="text-center">
                                <div className="pseudo-3d-bird-icon">
                                    <BirdIcon 
                                        bird={equippedBird} 
                                        className="icon !text-[10rem] sm:!text-[12rem]"
                                        imgClassName="w-[10rem] h-[10rem] sm:w-[12rem] sm:h-[12rem] drop-shadow-[0_20px_15px_rgba(0,0,0,0.7)]"
                                    />
                                </div>
                                <h2 className="name !text-2xl sm:!text-3xl">{equippedBird.name}</h2>
                            </div>
                        ) : (
                            <div className="text-center p-4 rounded-lg bg-black/30">
                                <p className="font-pixel text-2xl">Welcome to Bird Clash!</p>
                                <p className="mt-2">Visit the <span className="font-bold text-yellow-400">Store</span> or <span className="font-bold text-yellow-400">Birds</span> tab to get your first bird.</p>
                            </div>
                        )}
                    </div>

                    {/* Controls and Buttons */}
                    <div className="flex-shrink-0 max-w-sm mx-auto w-full flex flex-col justify-center items-center gap-4 p-2">
                        {isMatchmaking ? (
                            <div className="text-center p-4 bg-black/50 w-full rounded-lg border border-[var(--ff-border)]">
                                <h2 className="text-lg font-bold text-yellow-400 mb-2 font-pixel">Finding Match...</h2>
                                <p className="font-mono text-xl text-white mb-3">{formatTime(matchmakingTime)}</p>
                                <Spinner />
                                <Button onClick={onCancelMatchmaking} className="mt-4 w-full" variant="danger">Cancel</Button>
                            </div>
                        ) : (
                            <div className="w-full p-2 bg-black/50 space-y-2 border border-[var(--ff-border)] rounded-md">
                                <div className="grid grid-cols-2 gap-2">
                                    <button
                                        onClick={() => setSelectedMode('rank')}
                                        className={`p-1 border-2 transition-all duration-200 ${selectedMode === 'rank' ? 'bg-yellow-400/20 border-yellow-400' : 'bg-black/30 border-gray-600 hover:border-gray-400'}`}
                                    >
                                        <p className="font-pixel text-sm">RANKED</p>
                                        <p className="text-[10px] text-gray-300">1v1 Battle</p>
                                    </button>
                                    <button
                                        onClick={() => setSelectedMode('minigame')}
                                        className={`p-1 border-2 transition-all duration-200 ${selectedMode === 'minigame' ? 'bg-yellow-400/20 border-yellow-400' : 'bg-black/30 border-gray-600 hover:border-gray-400'}`}
                                    >
                                        <p className="font-pixel text-sm">MINI GAME</p>
                                        <p className="text-[10px] text-gray-300">Coin Rush</p>
                                    </button>
                                </div>

                                <div className="grid grid-cols-2 gap-2">
                                    <Button
                                        onClick={() => setIsCustomRoomModalOpen(true)}
                                        className="w-full !py-2 !text-lg"
                                        variant="secondary"
                                    >
                                        ROOM
                                    </Button>
                                    <Button
                                        onClick={() => {
                                            if (selectedMode === 'rank') {
                                                handleStartSoloMatchmaking();
                                            } else if (selectedMode === 'minigame') {
                                                props.onStartMinigame();
                                            }
                                        }}
                                        disabled={!hasBirds && selectedMode === 'rank'}
                                        className="w-full !py-2 !text-lg"
                                    >
                                        START
                                    </Button>
                                </div>
                                <Button onClick={props.onStartPractice} variant="secondary" className="w-full !py-2 !text-sm !bg-gray-700 hover:!bg-gray-600">
                                    🎯 PRACTICE MODE
                                </Button>

                                {matchmakingError && <p className="text-red-400 text-xs text-center">{matchmakingError}</p>}
                            </div>
                        )}
                    </div>
                </div>
            </main>

            {/* Bottom Nav */}
            <div className="sm:hidden">
              <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} hasUnreadGlobalMessages={hasUnreadGlobalMessages} />
            </div>

             {/* Modal-like Panel for other tabs */}
             {showContentPanel && (
                <div className="absolute inset-0 bg-black/70 backdrop-blur-sm z-20 flex items-center justify-center" onClick={() => setActiveTab('CHALLENGE')}>
                    <div className="w-full h-full max-w-4xl max-h-[85vh] bg-[var(--ff-bg)] border-2 border-[var(--ff-border)] shadow-2xl flex flex-col m-8" onClick={e => e.stopPropagation()}>
                        <div className="p-4 flex-shrink-0 border-b border-[var(--ff-border)] flex justify-between items-center">
                            <h2 className="font-pixel text-2xl text-yellow-400">{activeTab.replace('_', ' ')}</h2>
                            <button onClick={() => setActiveTab('CHALLENGE')} className="text-3xl hover:text-yellow-400">&times;</button>
                        </div>
                        <div className="flex-grow overflow-y-auto main-content-area p-4">
                            {renderPanelContent()}
                        </div>
                    </div>
                </div>
            )}

            <MailboxModal isOpen={isMailboxOpen} onClose={handleToggleMailbox} player={playerData} globalNotifications={notifications} />
            <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />
            <TopUpSelectionModal isOpen={isTopUpModalOpen} onClose={() => setIsTopUpModalOpen(false)} player={playerData} />
            {viewingProfileUid && <PublicProfileScreen uid={viewingProfileUid} onClose={() => setViewingProfileUid(null)} />}
            <MembershipClaimModal isOpen={!!membershipModalInfo} onClose={() => setMembershipModalInfo(null)} player={playerData} type={membershipModalInfo?.type || 'weekly'}/>
            <SeasonalEventModal isOpen={isWinterverseModalOpen} onClose={() => setIsWinterverseModalOpen(false)} />
            <EventsModal isOpen={isEventsModalOpen} onClose={() => setIsEventsModalOpen(false)} player={playerData} />
            <CustomRoomModal 
                isOpen={isCustomRoomModalOpen} 
                onClose={() => setIsCustomRoomModalOpen(false)} 
                player={playerData}
                onEnterRoom={onEnterRoom}
            />
        </div>
    );
};

export default Dashboard;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { Match, MatchResult, MatchPlayer, Player } from '../types';
import { rtdb } from '../services/firebase';
import * as playerService from '../services/playerService';
import type firebase from 'firebase/compat/app';
import Button from './common/Button';
import { getRankInfo } from '../utils/helpers';
import { Spinner } from './common/Spinner';
import { toast } from 'react-toastify';
import SettingsModal from './common/SettingsModal';
import PlayerAvatar from './common/PlayerAvatar';
import { useSettings } from '../hooks/useSettings';

interface ReportModalProps {
    opponentName: string;
    onClose: () => void;
    onSubmit: (category: string, details: string) => Promise<void>;
}

const ReportModal: React.FC<ReportModalProps> = ({ opponentName, onClose, onSubmit }) => {
    const [category, setCategory] = useState('cheating');
    const [details, setDetails] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        await onSubmit(category, details);
        setIsSubmitting(false);
    };

    return (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4" onClick={onClose}>
            <div className="w-full max-w-sm p-4 bg-[#2c2c54] border-2 border-black shadow-[6px_6px_0px_#000000]" onClick={e => e.stopPropagation()}>
                <h3 className="text-lg font-bold text-center mb-3 text-yellow-400">Report {opponentName}</h3>
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="text-sm font-bold">Reason</label>
                        <select value={category} onChange={e => setCategory(e.target.value)} className="pixel-input">
                            <option value="cheating">Cheating / Hacking</option>
                            <option value="abusive_language">Abusive Language / Harassment</option>
                            <option value="inappropriate_name">Inappropriate Name</option>
                            <option value="other">Other</option>
                        </select>
                    </div>
                    <div>
                        <label className="text-sm font-bold">Details (Optional)</label>
                        <textarea value={details} onChange={e => setDetails(e.target.value)} rows={3} placeholder="Provide more information..." className="pixel-input" />
                    </div>
                    <div className="flex gap-4 pt-2">
                        <Button type="button" onClick={onClose} variant="secondary" className="w-full">Cancel</Button>
                        <Button type="submit" disabled={isSubmitting} variant="danger" className="w-full">
                            {isSubmitting ? <Spinner /> : "Submit Report"}
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    );
};

interface GameScreenProps {
  match: Match;
  currentPlayer: Player;
  onGameOver: (result: MatchResult, match: Match) => void;
}

const DEFAULT_EMOTES = ['👍', '😂', '😭', '🔥', '👋', 'GG'];

const EmoteBubble: React.FC<{ payload: { emote: string; key: string } | null }> = ({ payload }) => {
    if (!payload) return null;
    return (
        <div key={payload.key} className="absolute -top-16 left-1/2 -translate-x-1/2 z-10 pointer-events-none">
            <div className="bg-white/90 text-black text-5xl p-3 rounded-full border-4 border-black shadow-lg animate-emote-popup animate-emote-fadeout">
                {payload.emote}
            </div>
        </div>
    );
};

const ReactionAnimation: React.FC<{ payload: { reaction: string; targetPlayerUid: string; key: string } | null, playerRefs: React.RefObject<Map<string, HTMLDivElement>> }> = ({ payload, playerRefs }) => {
    if (!payload || !playerRefs.current) return null;

    const targetEl = playerRefs.current.get(payload.targetPlayerUid);
    if (!targetEl) return null;

    const rect = targetEl.getBoundingClientRect();

    return (
        <div 
            key={payload.key} 
            className="absolute pointer-events-none z-20"
            style={{ top: `${rect.top + rect.height / 2}px`, left: `${rect.left + rect.width / 2}px` }}
        >
            <div className="text-7xl animate-reaction-float-up -translate-x-1/2 -translate-y-1/2">
                {payload.reaction}
            </div>
        </div>
    );
};


const GameScreen: React.FC<GameScreenProps> = ({ match, currentPlayer, onGameOver }) => {
  const currentUserId = currentPlayer.uid;
  const [gameState, setGameState] = useState<Match>(match);
  const [gameError, setGameError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [damageNumbers, setDamageNumbers] = useState<{ amount: number; target: 'me' | 'opponent'; key: number, isCrit?: boolean }[]>([]);
  const [animationClasses, setAnimationClasses] = useState({ me: '', opponent: '', screen: '' });
  const [isEmotePanelOpen, setIsEmotePanelOpen] = useState(false);
  const [emoteCooldown, setEmoteCooldown] = useState(false);
  const [emoteDisplay, setEmoteDisplay] = useState<{ me: { emote: string; key: string } | null; opponent: { emote: string; key: string } | null }>({ me: null, opponent: null });
  const [reactionDisplay, setReactionDisplay] = useState<{ reaction: string; targetPlayerUid: string; key: string } | null>(null);
  const [gameOverState, setGameOverState] = useState<'win' | 'loss' | 'draw' | null>(null);
  const lastEmoteKey = useRef<string | null>(null);
  const lastReactionKey = useRef<string | null>(null);
  const playerRefs = useRef(new Map<string, HTMLDivElement>());
  const { fastAnimationMode } = useSettings();

  const gameOverHandled = useRef(false);
  const prevHealthRef = useRef<{ me?: number; opponent?: number }>({});

  // Listen for game state changes from Firebase
  useEffect(() => {
    const matchRef = rtdb.ref(`matches/${match.id}`);
    const listener = (snapshot: firebase.database.DataSnapshot) => {
      const data = snapshot.val() as Match;
      if (data) {
        setGameState(data);
      }
    };
    const errorListener = (error: Error) => {
        setGameError("Connection lost. The game cannot continue.");
    };

    matchRef.on('value', listener, errorListener);
    return () => matchRef.off('value', listener);
  }, [match.id]);

  useEffect(() => { setGameState(match) }, [match]);

  const { me, opponent } = useMemo(() => {
    if (!gameState) return { me: null, opponent: null };
    if (gameState.player1.uid === currentUserId) {
      return { me: gameState.player1, opponent: gameState.player2 };
    }
    return { me: gameState.player2, opponent: gameState.player1 };
  }, [gameState, currentUserId]);

  const myEmotes = useMemo(() => {
    const equipped = me?.equippedEmotes;
    if (!equipped || equipped.length === 0) return DEFAULT_EMOTES;
    const combined = [...equipped];
    const equippedSet = new Set(equipped);
    for (const defaultEmote of DEFAULT_EMOTES) {
        if (combined.length >= 6) break;
        if (!equippedSet.has(defaultEmote)) combined.push(defaultEmote);
    }
    return combined.slice(0, 6);
  }, [me]);

  const isOpponentBot = useMemo(() => opponent?.isBot === true, [opponent]);

  // Calculate potential damage for preview
  const potentialDamage = useMemo(() => {
      if (!me || !opponent) return 0;
      let damage = me.selectedBird.skillPower;

      // Adrenaline check (if health < 30%)
      if (me.currentHealth / me.selectedBird.maxHealth <= 0.3) {
          damage = Math.floor(damage * 1.2);
      }

      if (opponent.activeEffects?.defenseBuff) {
          damage = Math.floor(damage * 0.5);
      }
      return damage;
  }, [me, opponent]);

  useEffect(() => {
    const emoteData = gameState.lastEmote;
    if (emoteData && emoteData.key !== lastEmoteKey.current) {
        lastEmoteKey.current = emoteData.key;
        const isMe = emoteData.senderUid === currentUserId;
        const emotePayload = { emote: emoteData.emote, key: emoteData.key };
        if (isMe) setEmoteDisplay(prev => ({ ...prev, me: emotePayload }));
        else setEmoteDisplay(prev => ({ ...prev, opponent: emotePayload }));
    }

    const reactionData = gameState.lastReaction;
    if (reactionData && reactionData.key !== lastReactionKey.current) {
        lastReactionKey.current = reactionData.key;
        setReactionDisplay({
            reaction: reactionData.reaction,
            targetPlayerUid: reactionData.targetPlayerUid,
            key: reactionData.key,
        });
        setTimeout(() => setReactionDisplay(null), 1500);
    }

    const newMe = gameState.player1.uid === currentUserId ? gameState.player1 : gameState.player2;
    const newOpponent = gameState.player1.uid === currentUserId ? gameState.player2 : gameState.player1;

    const myDamageTaken = (prevHealthRef.current.me ?? newMe.currentHealth) - newMe.currentHealth;
    const opponentDamageTaken = (prevHealthRef.current.opponent ?? newOpponent.currentHealth) - newOpponent.currentHealth;

    // Detect Crits based on damage jumps (simple heuristic since we don't store "isCrit" in Firebase state for simplicity)
    // A crit is usually > base power.
    const isMyAttackCrit = opponentDamageTaken > (newMe.selectedBird.skillPower * 1.3); // Rough check
    const isOpponentAttackCrit = myDamageTaken > (newOpponent.selectedBird.skillPower * 1.3);

    if (opponentDamageTaken > 0) {
        setAnimationClasses({ me: 'anim-attack-me', opponent: 'anim-hit-reaction', screen: '' });
        setDamageNumbers(prev => [...prev, { amount: opponentDamageTaken, target: 'opponent', key: Date.now(), isCrit: isMyAttackCrit }]);
    }
    if (myDamageTaken > 0) {
        setAnimationClasses({ me: 'anim-hit-reaction', opponent: 'anim-attack-opponent', screen: 'anim-screen-shake' });
        setDamageNumbers(prev => [...prev, { amount: myDamageTaken, target: 'me', key: Date.now(), isCrit: isOpponentAttackCrit }]);
    }
    if (myDamageTaken > 0 || opponentDamageTaken > 0) {
        const animDuration = fastAnimationMode ? 300 : 600;
        setTimeout(() => setAnimationClasses({ me: '', opponent: '', screen: '' }), animDuration);
        setTimeout(() => setDamageNumbers(prev => prev.filter(dn => dn.key !== Date.now())), 1000);
    }
    prevHealthRef.current = { me: newMe.currentHealth, opponent: newOpponent.currentHealth };

    if (gameState.status === 'finished' && !gameOverHandled.current) {
        gameOverHandled.current = true;
        let outcome: 'win' | 'loss' | 'draw' = 'draw';
        if (gameState.winner === currentUserId) outcome = 'win';
        else if (gameState.winner && gameState.winner !== 'draw') outcome = 'loss';

        setGameOverState(outcome);

        setTimeout(() => {
            onGameOver({
                outcome,
                myDamageDealt: newMe.damageDealt,
                opponentDamageDealt: newOpponent.damageDealt,
                matchType: gameState.matchType,
            }, gameState);
        }, 2500);
    }
  }, [gameState, currentUserId, onGameOver, fastAnimationMode]);

  const isGameActive = gameState.status === 'active';
  const isMyTurn = isGameActive && gameState.currentTurnPlayerUid === currentUserId;

  const handleAttack = useCallback(() => {
    if (!isMyTurn || isSubmitting) return;

    setIsSubmitting(true);
    const matchRef = rtdb.ref(`matches/${match.id}`);
    matchRef.transaction(currentData => {
        if (!currentData || currentData.status !== 'active' || currentData.currentTurnPlayerUid !== currentUserId) return;
        const meKey = currentData.player1.uid === currentUserId ? 'player1' : 'player2';
        const opponentKey = meKey === 'player1' ? 'player2' : 'player1';

        let damage = currentData[meKey].selectedBird.skillPower;
        let isCrit = false;

        // --- Critical Hit Logic (15% Chance) ---
        // ESPORTS UPDATE: Disable RNG in Ranked Matches
        if (currentData.matchType !== 'rank') {
            if (Math.random() < 0.15) {
                damage = Math.floor(damage * 1.5);
                isCrit = true;
            }
        }

        // --- Adrenaline Logic (Comeback) ---
        // If Health < 30%, boost damage by 20%
        if ((currentData[meKey].currentHealth / currentData[meKey].selectedBird.maxHealth) <= 0.3) {
            damage = Math.floor(damage * 1.2);
            if (!currentData[meKey].activeEffects) currentData[meKey].activeEffects = {};
            currentData[meKey].activeEffects.adrenaline = true; // Visual marker
        }

        // --- Defense Calculation ---
        if (currentData[opponentKey].activeEffects?.defenseBuff) {
            damage = Math.floor(damage * 0.5);
            // Consume buff if it's a one-time hit (optional, keeping consistent with old logic if desired, or make it persistent for turn)
            delete currentData[opponentKey].activeEffects.defenseBuff;
        }

        // --- Apply Damage ---
        currentData[opponentKey].currentHealth -= damage;
        currentData[meKey].damageDealt += damage;

        if (!currentData.log) currentData.log = [];
        const msg = isCrit ? `${currentData[meKey].displayName} lands a CRITICAL HIT for ${damage}!` : `${currentData[meKey].displayName} attacks for ${damage} damage!`;
        currentData.log.push(msg);

        if (currentData[opponentKey].currentHealth <= 0) {
            currentData.winner = currentUserId;
            currentData.status = 'finished';
            currentData.log.push(`${currentData[meKey].displayName} wins!`);
            return currentData;
        }
        if (currentData.turn >= 10) {
            currentData.status = 'finished';
            const p1Health = currentData.player1.currentHealth;
            const p2Health = currentData.player2.currentHealth;
            if (p1Health > p2Health) currentData.winner = currentData.player1.uid;
            else if (p2Health > p1Health) currentData.winner = currentData.player2.uid;
            else currentData.winner = 'draw';
            currentData.log.push(`Time's up! Winner by health.`);
            return currentData;
        }
        currentData.turn += 1;
        currentData.currentTurnPlayerUid = currentData[opponentKey].uid;
        return currentData;
    }).catch(error => toast.error("Attack failed."))
      .finally(() => setIsSubmitting(false));
  }, [isMyTurn, isSubmitting, currentUserId, match.id]);

  const handleSendEmote = useCallback((emote: string) => {
      if (emoteCooldown) {
          toast.info("Please wait before sending another emote.");
          return;
      }
      const emotePayload = {
          senderUid: currentUserId,
          emote,
          key: Date.now().toString(),
      };
      rtdb.ref(`matches/${match.id}/lastEmote`).set(emotePayload).catch(err => {
          toast.error("Could not send emote.");
      });
      setEmoteCooldown(true);
      setTimeout(() => setEmoteCooldown(false), 2000); // 2 second cooldown
  }, [emoteCooldown, currentUserId, match.id]);

  useEffect(() => {
    // Bot logic
    if (isOpponentBot && gameState.currentTurnPlayerUid === opponent?.uid && gameState.status === 'active') {
        const botAttackDelay = fastAnimationMode ? 500 : Math.random() * 2000 + 1000;
        const timeoutId = setTimeout(() => {
            const matchRef = rtdb.ref(`matches/${match.id}`);
            matchRef.transaction(currentData => {
                if (!currentData || currentData.status !== 'active' || currentData.currentTurnPlayerUid !== opponent?.uid) return;
                const meKey = currentData.player1.uid === currentUserId ? 'player1' : 'player2';
                const opponentKey = meKey === 'player1' ? 'player2' : 'player1';

                let damage = currentData[opponentKey].selectedBird.skillPower;
                let isCrit = false;

                // Bot Crit (10% chance)
                // ESPORTS: No RNG in ranked
                if (currentData.matchType !== 'rank') {
                    if (Math.random() < 0.1) {
                        damage = Math.floor(damage * 1.5);
                        isCrit = true;
                    }
                }

                // Bot Adrenaline
                if ((currentData[opponentKey].currentHealth / currentData[opponentKey].selectedBird.maxHealth) <= 0.3) {
                    damage = Math.floor(damage * 1.2);
                }

                currentData[meKey].currentHealth -= damage;
                currentData[opponentKey].damageDealt += damage;

                if (!currentData.log) currentData.log = [];
                const msg = isCrit ? `Bot lands a CRITICAL HIT for ${damage}!` : `Bot attacks for ${damage} damage!`;
                currentData.log.push(msg);

                if (currentData[meKey].currentHealth <= 0) {
                    currentData.winner = opponent?.uid;
                    currentData.status = 'finished';
                    currentData.log.push(`Bot wins!`);
                    return currentData;
                }
                if (currentData.turn >= 10) {
                    currentData.status = 'finished';
                    const p1Health = currentData.player1.currentHealth;
                    const p2Health = currentData.player2.currentHealth;
                    if (p1Health > p2Health) currentData.winner = currentData.player1.uid;
                    else if (p2Health > p1Health) currentData.winner = currentData.player2.uid;
                    else currentData.winner = 'draw';
                    currentData.log.push(`Time's up! Winner by health.`);
                    return currentData;
                }
                currentData.turn += 1;
                currentData.currentTurnPlayerUid = currentData[meKey].uid;
                return currentData;
            }).catch(error => console.error("Bot attack failed.", error));
        }, botAttackDelay);

        return () => clearTimeout(timeoutId);
    }
  }, [gameState, isOpponentBot, opponent, currentUserId, match.id, fastAnimationMode]);

  const handleReportSubmit = async (category: string, details: string) => {
    try {
        await playerService.submitReport(currentPlayer, category, details, opponent, match.id);
        toast.success("Report submitted. Thank you for helping keep the community safe.");
        setIsReportModalOpen(false);
    } catch (e: any) {
        toast.error(`Failed to submit report: ${e.message}`);
    }
  };

  if (gameError) {
    return (
        <div className="flex flex-col items-center justify-center min-h-[80vh] text-center p-4">
            <h2 className="text-xl font-bold text-red-400 mb-4">Game Error</h2>
            <p className="text-gray-300 mb-6">{gameError}</p>
            <Button onClick={() => onGameOver({ outcome: 'draw', myDamageDealt: 0, opponentDamageDealt: 0, matchType: match.matchType }, match)}>
                Return to Lobby
            </Button>
        </div>
     )
  }

  if (!me || !opponent) {
      return <div className="flex justify-center items-center h-full"><Spinner /></div>;
  }

  const isP1 = me.uid === gameState.player1.uid;
  const p1MovesLeft = 5 - Math.floor((gameState.turn - 1) / 2);
  const p2MovesLeft = 5 - Math.floor(gameState.turn / 2);
  const myMovesLeft = isP1 ? p1MovesLeft : p2MovesLeft;
  const opponentMovesLeft = isP1 ? p2MovesLeft : p1MovesLeft;

  const isRanked = match.matchType === 'rank';

  return (
    <div className={`flex flex-col h-full p-4 relative overflow-hidden ${animationClasses.screen}`}>
      <PlayerDisplay player={opponent} isTurn={!isMyTurn && isGameActive} movesLeft={opponentMovesLeft} isP1={!isP1} />

        <div className="flex-grow flex items-center justify-around my-4 bg-black/20 border-2 border-black p-4 relative overflow-hidden">
            {damageNumbers.map(dn => (
                <div key={dn.key} className={`absolute pointer-events-none animate-damage-popup ${dn.target === 'me' ? 'left-1/4' : 'right-1/4'}`}>
                    <span className={`text-5xl font-bold ${dn.isCrit ? 'text-red-600 scale-150' : 'text-red-500'}`}>-{dn.amount}</span>
                    {dn.isCrit && <div className="text-yellow-400 font-bold text-xl uppercase animate-bounce absolute -top-10 left-0 w-32 text-center">CRITICAL!</div>}
                </div>
            ))}

            <div className={`relative ${animationClasses.opponent}`}>
                {/* Fix: Use a block statement for the ref callback to ensure a void return type. */}
                <div ref={el => { if (el) playerRefs.current.set(opponent.uid, el); }}>
                    <EmoteBubble payload={emoteDisplay.opponent} />
                    <span className="text-8xl md:text-9xl transform -scale-x-100">{opponent.selectedBird.icon}</span>
                </div>
            </div>

             <div className="absolute top-2 left-1/2 -translate-x-1/2 text-center bg-black/50 p-2 border-2 border-black z-10 w-48">
                {isRanked && (
                    <div className="bg-yellow-600 text-black text-[10px] font-bold uppercase mb-1 px-1 border border-black animate-pulse">
                        Fair Play: Stats Normalized
                    </div>
                )}
                <h2 className="text-xl font-bold text-yellow-400">
                    {isGameActive ? (isMyTurn ? "Your Turn!" : `${opponent.displayName}'s Turn`) : "Match Over"}
                </h2>
                <p className="text-xs">Turn: {gameState.turn}</p>
            </div>

            <div className={`relative ${animationClasses.me}`}>
                 {/* Fix: Use a block statement for the ref callback to ensure a void return type. */}
                 <div ref={el => { if (el) playerRefs.current.set(me.uid, el); }}>
                    <EmoteBubble payload={emoteDisplay.me} />
                    <span className="text-8xl md:text-9xl">{me.selectedBird.icon}</span>
                </div>
            </div>
             {gameOverState && (
                <div className="game-over-overlay">
                    {gameOverState === 'win' && <h1 className="game-over-text victory-text">VICTORY</h1>}
                    {gameOverState === 'loss' && <h1 className="game-over-text defeat-text">DEFEAT</h1>}
                    {gameOverState === 'draw' && <h1 className="game-over-text draw-text">DRAW</h1>}
                </div>
            )}
            <ReactionAnimation payload={reactionDisplay} playerRefs={playerRefs} />
        </div>

        <PlayerDisplay player={me} isTurn={isMyTurn && isGameActive} movesLeft={myMovesLeft} isP1={isP1} />

        <div className="h-28 mt-4 flex justify-center items-center gap-4">
             <div className="flex-shrink-0 flex gap-2">
                <button onClick={() => setIsEmotePanelOpen(prev => !prev)} className="w-16 h-16 bg-gray-800 border-2 border-black text-3xl">😊</button>
                {!isOpponentBot && <button onClick={() => setIsReportModalOpen(true)} className="w-16 h-16 bg-gray-800 border-2 border-black text-3xl">🚩</button>}
             </div>

             <Button onClick={handleAttack} disabled={!isMyTurn || isSubmitting} className="w-full max-w-xs !h-20 !text-xl flex flex-col items-center justify-center">
                {isSubmitting ? <Spinner /> : (
                    <>
                        <span>ATTACK!</span>
                        <span className="text-sm font-normal text-yellow-200">~{potentialDamage} dmg</span>
                    </>
                )}
             </Button>

             <div className="flex-shrink-0">
                <button onClick={() => setIsSettingsOpen(true)} className="w-16 h-16 bg-gray-800 border-2 border-black flex items-center justify-center text-3xl">⚙️</button>
             </div>
        </div>

        {isEmotePanelOpen && (
            <div className="absolute bottom-40 left-1/2 -translate-x-1/2 z-20 p-2 bg-black/80 border-2 border-black grid grid-cols-3 gap-2">
                {myEmotes.map(emote => (
                    <button key={emote} onClick={() => handleSendEmote(emote)} className="text-4xl p-2 hover:bg-white/20 rounded-lg">{emote}</button>
                ))}
            </div>
        )}

        <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />
        {isReportModalOpen && <ReportModal opponentName={opponent.displayName || 'Opponent'} onClose={() => setIsReportModalOpen(false)} onSubmit={handleReportSubmit} />}
    </div>
  );
};


