    const isAdrenaline = (player.currentHealth / player.selectedBird.maxHealth) <= 0.3;

    return (
    <div className={`p-2 ${bgColor} border-2 ${borderColor} ${turnIndicatorBorder} shadow-lg transition-all duration-300 ${isTurn ? 'scale-105' : ''} relative`}>
        {isAdrenaline && <div className="absolute inset-0 border-4 border-red-500 animate-pulse pointer-events-none z-10" title="Adrenaline Rush!"></div>}
        <div className="flex justify-between items-start relative z-20">
            <div className="flex items-center gap-2">
                <PlayerAvatar 
                    photoURL={player.photoURL}
                    uid={player.uid}
                    activeBadge={player.activeBadge}
                    sizeClassName="w-12 h-12"
                    imgClassName="border-2 border-black bg-gray-600"
                />
                <div>
                    <p className="font-pixel text-sm text-white leading-tight">{player.displayName}</p>
                    <p className="font-semibold text-xs text-blue-300 leading-tight">{rankName}</p>
                    {isAdrenaline && <p className="text-[10px] text-red-400 font-bold uppercase animate-bounce">🔥 Adrenaline!</p>}
                </div>
            </div>
            <div className="text-right flex-shrink-0 ml-2">
                <p className="font-pixel text-sm text-white mt-1">Moves: {movesLeft}</p>
            </div>
        </div>
        <div className="mt-2 w-full bg-black h-5 border border-black p-0.5 relative z-20">
            <div 
              className={`h-full transition-all duration-300 ${isAdrenaline ? 'bg-red-600' : 'bg-gradient-to-r from-red-600 via-yellow-500 to-yellow-400'}`} 
              style={{ width: `${Math.max(0, healthPercent)}%`}}
            ></div>
            <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white font-pixel" style={{textShadow:'1px 1px 0 #000'}}>{Math.max(0, player.currentHealth)} / {player.selectedBird.maxHealth}</span>
        </div>
    </div>
  )};

